class Solution:
    def maxSatisfaction(self, satisfaction):
        satisfaction.sort()
        result = 0
        suffix_sum = 0
        for s in reversed(satisfaction):
            suffix_sum += s
            if suffix_sum <= 0:
                break
            result += suffix_sum
        return result

