var maxSatisfaction = function(satisfaction) {
    satisfaction.sort((a, b) => a - b);
    let result = 0, suffixSum = 0;
    for (let i = satisfaction.length - 1; i >= 0; i--) {
        suffixSum += satisfaction[i];
        if (suffixSum <= 0) break;
        result += suffixSum;
    }
    return result;
};
